                    <h4 className="font-bold text-slate-900 mb-1 italic tracking-tight">{item.title}</h4>
                    <p className="text-sm text-slate-500 font-medium">{item.desc}</p>
                  </div>
                ))}
              </div>

            </div>
          </ScrollReveal>

        </div>
      </div>
    </section>
  );
};

export default About;

